VALUES
  ('judicial-de09bf8b-moex-00059', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', 'A為某大學學生認受教師 B性霸凌，除在臉書發動公審外，並向學校申
請調查，後經學校所設之性別平等教育委員會調查完成，決議成立性霸
凌，並建議應解聘 B，管制 4 年。校教評會最後決議停聘 2 年，以儆效
尤。B 對此結果不服，向教育部中央教師申訴評議委員會提起申訴，經
維持學校原處分後，B 再向行政法院提起撤銷訴訟。於法院審理中，學
校援引性別平等教育法第41 條第 2 項：「法院對於前項事實之認定，應
審酌各級性別平等教育委員會之調查報告」，認法院對於系爭性霸凌之
認定，應受學校性別平等教育委員會決議之拘束，至多只能審查學校處
分之輕重。針對學校性別平等教育委員會決議、教評會決議、行政法院
審理裁判之不同階段，是否存有判斷餘地、裁量餘地等一定拘束關係？
請分析之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "84065353645f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00060', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '某股份有限公司進入破產程序中，其董事 A 以損害債權人為目的，故
意捏造債務、承認不真實之債務，涉有詐欺破產罪，其被害人數逾百
人，被害金額約新臺幣二千餘萬元。內政部移民署依「國民涉嫌重大
經濟犯罪重大刑事案件或有犯罪習慣不予許可或禁止入出國認定標
準」第 2 條：「國民涉及下列各款罪嫌，且被害人數在三十人以上或被
害金額或所獲利益在新臺幣三千萬元以上者，應認定其涉嫌重大經濟
犯罪」，於接獲相關檢警機關通知後，應即禁止 A 出國。惟移民署錯看
法條，誤以為相對人須同時滿足「被害人數與被害金額」兩項要件，
認不應禁止其出國，是並未據以執行。A 經探詢移民署承辦人員後，
閱讀相關規定，獲知竟未遭限制出境，大喜過望，遂即快馬加鞭，在
機場航空公司櫃檯以現金購買頭等艙機票前往美國，但於辦理出境手
續時，因相關人員查詢資料而存疑，後於現場決定不准 A 出境，致其
蒙受機票與美國數日住宿費之損失，A 遂向移民署請求國家賠償。請
問 A 之請求是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "84065353645f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00061', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '臺北市立圖書館推廣活動委員會審議通過，訂定實施臺北市立圖書館影
視拍攝須知，該須知第 5 點第 4款明定，如有未依申請範圍拍攝之情形，
該館得要求申請人立即停止使用。現有民眾 A 向臺北市立圖書館 B 分
館，申請非商業影片拍攝，經核准後即進行拍攝作業，惟過程中發生是
否有逾原申請範圍之爭執，B 分館即援引前開拍攝須知相關規定，立即
要求 A停止拍攝工作，並即刻離開該館，A則以系爭須知無法律依據，
不符法律保留原則，圖書館乃公共空間、渠等並無干擾環境安寧及衛生
等情事，拒絕離開，並認 B分館違法。請分析之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "84065353645f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00062', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-d1a761c9', 'sub-judicial-de09bf8b-04', NULL, 'essay', '政治受難者 A數十年前因涉入政治案件而遭法院判處 6個月有期徒刑，
但得易科罰金，A當時亦如實繳納罰金在案。現A之案件，經認定確屬
促進轉型正義條例第 6條之 1所稱國家之司法不法行為，A已死亡，其
家屬遂依威權統治時期國家不法行為被害者權利回復條例第10條規定：
「因國家不法行為致財產所有權被剝奪之被害者，得檢附具體資料，以
書面向權利回復基金會申請權利回復；被害者死亡，得由其家屬申請
之」，請求財團法人威權統治時期國家不法行為被害者權利回復基金會，
賠償其「與罰金數額相當」之被剝奪的財產。請分析 A之家屬的主張是
否有理由？如遭基金會駁回，應如何提起救濟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "84065353645f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00063', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'essay', '甲與朋友飲酒作樂數小時後開車離去，但因酒後精神恍惚導致車輛失控
撞毀停在路邊 A的機車，甲心虛逃離。隔天 A報警，警察乙調閱監視器
畫面過濾出可能是甲肇事，乃通知甲至警局約談，甲在警詢中坦承係其
酒駕撞毀 A車，警察乙誤以為甲既然認罪，即屬公共危險罪之「現行犯」，
乃當場將甲依現行犯予以逮捕並上銬，但事實上甲此種情形並不符合刑
事訴訟法的現行犯要件。試問本案中甲、乙可能應負之刑責。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00064', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'essay', '甲為調查其配偶 A 之婚外情，趁機輸入私下偷記的密碼登入 A 的手機
查看，果然發現A與 B發生婚外性行為的親密對話，甲為取證乃將相關
對話截圖，並將該對話截圖從 A的手機轉寄到自己的手機予以存檔。之
後，甲找 B理論並威脅「除非你依本地習俗至市場舉牌懺悔下跪幫我洗
門風，否則就上法院告你」，B為避免被告遂至市場舉牌懺悔下跪。試問
本案中甲可能應負之刑責。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00065', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關行為後法律有變更之效果，下列敘述何者正確？', '["刑罰一律適用裁判時之法律", "拘束人身自由之保安處分一律適用行為時之法律", "非拘束人身自由之保安處分一律適用行為時之法律", "違禁物之沒收一律適用裁判時法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00066', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '對於「罪刑法定主義」之敘述，下列何者錯誤？', '["罪與刑須法律明文規定", "法律未規定之行為不得處罰", "即便不利於行為人亦得類推適用以補充法律之不足", "犯罪之成立，須有立法院通過之成文法為其依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00067', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關保證人地位之敘述，下列何者正確？', '["夫妻於離婚後分居，仍互負保證人地位", "即使醫師明確拒絕看診而不讓病患進入醫院，對其仍負保證人地位", "保母甲與乙約定週末幫忙照顧乙之嬰兒，甲自約定時起即負保證人地位", "甲在戲院看電影，戲院發生大火，甲對鄰座乙不負保證人地位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00068', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法阻卻違法事由之規定，下列敘述何者錯誤？', '["逮捕現行犯之行為，可主張依法令之行為", "遇火災時，未得鄰居同意而進入其樓層住所躲避，可主張緊急避難", "鄰居指揮其飼養之比特犬攻擊他人時，該他人可主張正當防衛", "遭遇山難時，侵入他人於山上的別墅覓食的行為，可主張自助行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
